import test from 'node:test';
import assert from 'node:assert/strict';

import { JobStore } from '../src/job-store.mjs';
import { JobRunner } from '../src/job-runner.mjs';

test('a late failure cannot send a replacement attempt back to the queue', () => {
  const store = new JobStore();
  store.enqueue('export-20', { format: 'xlsx' });

  const original = store.claim();
  store.requeueRunning('export-20', 'watchdog recovery');
  const replacement = store.claim();

  assert.equal(store.fail('export-20', original.attempt, new Error('late socket error')), false);
  assert.equal(store.get('export-20').status, 'running');
  assert.equal(store.get('export-20').attempt, replacement.attempt);

  assert.equal(store.complete('export-20', replacement.attempt, 'replacement-result'), true);
  assert.equal(store.get('export-20').status, 'succeeded');
  assert.equal(store.get('export-20').result, 'replacement-result');
});

test('the runner identifies the claim when reporting failed work', async () => {
  const calls = [];
  const failure = new Error('render process exited');
  const store = {
    claim() {
      return { id: 'export-21', payload: { format: 'pdf' }, attempt: 12 };
    },
    complete() {
      throw new Error('unexpected completion');
    },
    fail(...args) {
      calls.push(args);
      return true;
    }
  };

  const runner = new JobRunner(store, async () => {
    throw failure;
  });
  assert.equal((await runner.runNext()).status, 'queued');
  assert.equal(calls.length, 1);
  assert.equal(calls[0][0], 'export-21');
  assert.equal(calls[0][1], 12);
  assert.strictEqual(calls[0][2], failure);
});
